window.TREE_SCRIPT={HEAPIFY:{START:()=>`Let's build a Max-Heap! Our mission is to make sure every parent is larger than its children.`,COMPARING:(e,t)=>`Checking parent ${e} against child ${t}. The parent must be the boss!`,SWAPPING:(e,t)=>`Aha! Child ${t} is bigger than parent ${e}. Let's swap them and bubble the value up!`,DONE:()=>`This subtree now follows the Max-Heap rule. Perfect structure!`},BST:{START:()=>`Welcome to the Binary Search Tree! Here, smaller numbers go left and larger numbers go right. It's perfectly organized.`,INSERT:e=>`Inserting ${e}. Let's follow the rules to find its new home.`,SEARCH:(e,t)=>`Looking for ${e}. At node ${t}... should we go left or right?`,FOUND:e=>`Found it! There's our target value ${e}.`,NOT_FOUND:e=>`We've reached the end and didn't find ${e}. It's not in our tree!`,DELETE:e=>`Removing ${e}. We'll need to carefully stitch the tree back together.`,COMPARING:(e,t)=>`Comparing ${e} with ${t}.`},AVL:{START:()=>`This is an AVL Tree! It's a BST that balances itself automatically using rotations. It never gets too lopsided.`,INSERT:e=>`Inserting ${e}. Let's find its place and ensure the tree remains perfectly balanced.`,SEARCH:(e,t)=>`Searching for ${e}. Current node: ${t}. AVL trees make searching super fast!`,FOUND:e=>`Found ${e}! The tree structure kept our search path short and efficient.`,NOT_FOUND:e=>`${e} is not in the tree. We checked the entire path in O(log n) time.`,DELETE:e=>`Removing ${e}. After removal, we might need to re-balance the tree from the bottom up.`,IMBALANCE:e=>`Node ${e} is out of balance! The height difference is too big.`,ROTATE_LEFT:e=>`Performing a Left Rotation on ${e} to restore balance. Swing it round!`,ROTATE_RIGHT:e=>`Performing a Right Rotation on ${e}. Pivot and shift!`,BALANCED:()=>`The tree is perfectly balanced once again. Efficient and fast!`},BPLUS:{START:e=>`Welcome to the B+ Tree! This is a multi-way search tree with an order of ${e}. All values live in the leaf level.`,INSERT:e=>`Inserting ${e}. Let's traverse down to the leaf level where all our actual data lives.`,SEARCH:e=>`Searching for ${e}. We follow the internal node pointers to reach the correct leaf bucket.`,LEAF_REACHED:e=>`We've reached leaf node [${e.join(`, `)}]. This is where the actual data resides!`,SPLIT_LEAF:()=>`Leaf full! Splitting and copying the smallest key from the new leaf to the parent.`,SPLIT_INTERNAL:()=>`Internal node full! Splitting and moving the middle key to the parent node.`,PROMOTE:e=>`Promoting key ${e} to keep the tree balanced.`,SUCCESS:()=>`Operation complete! The B+ tree is perfectly balanced and optimized for range scans.`},BTREE:{START:e=>`Welcome to the B-Tree! This is a balanced search tree designed for high-performance storage.`,INSERT:e=>`Inserting ${e}. Unlike B+ trees, keys in a B-Tree can reside in internal nodes as well.`,SEARCH:e=>`Searching for ${e}. We check each node's keys; if not found, we follow the correct child pointer.`,NODE_REACHED:e=>`Current node: [${e.join(`, `)}]. Let's check if our value is here or if we go deeper.`,SPLIT:()=>`Node overflow! We must split this node and promote the median key to maintain tree constraints.`,PROMOTE:e=>`Promoting ${e} to the parent node.`,SUCCESS:()=>`B-Tree operation finished. The structure remains perfectly balanced.`}};